generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring input current of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData RobotAxisDataStream
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder mounted directly on the motor shaft providing motor angle (r_M) measurements"
    DTDFVocab:producedData RobotAxisDataStream
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the cycloidal gearbox providing gearbox output angle (r_G) measurements"
    DTDFVocab:producedData RobotAxisDataStream
]

// C4: Physical‑to‑virtual interaction (data transmitted)
instance RobotAxisDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor, MotorEncoderSensor, GearboxEncoderSensor
]

// C10: Data objects (measured and derived)
instance MeasuredCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of measured motor current I_M streamed via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

instance MeasuredMotorAngleData : DTDFVocab:Data [
    base:desc "Time‑series of motor shaft angle r_M streamed via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

instance MeasuredGearboxAngleData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox output angle r_G streamed via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ calculated from current and angle data, provided as a time‑series via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

instance DerivedAngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω (rad/s) calculated from angle traces, streamed via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

instance DerivedAccelerationData : DTDFVocab:Data [
    base:desc "Derived angular acceleration α calculated from angular velocity traces, streamed via MQTT"
    DTDFVocab:fromData RobotAxisDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

// C11: Enablers
instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker enabling live, real‑time streaming of sensor data to the digital shadow"
    DTDFVocab:enables RealTimeVisualizationService, FrictionIdentificationService, SimulationComparisonService
]

instance SimulinkExecutorEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment running motor, gearbox and friction simulation models"
    DTDFVocab:enables SimulationComparisonService, FrictionIdentificationService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) providing standardized integration of models and data"
    DTDFVocab:enables SimulationComparisonService, FrictionIdentificationService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard component visualizing measured and simulated data streams"
    DTDFVocab:enables RealTimeVisualizationService
]

// C10: Engineering and Simulation Models
instance MotorModel : DTDFVocab:Model [
    base:desc "SysML block and Simulink executable model of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

instance GearboxModel : DTDFVocab:Model [
    base:desc "SysML block and Simulink executable model of the cycloidal gearbox transmission"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

instance FrictionModelCoulombViscous : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Coulomb‑Viscous behavior for the gearbox"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

instance FrictionModelStribeck : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Stribeck effect for the gearbox"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

instance FrictionModelDahl : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Dahl characteristics for the gearbox"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

instance FrictionModelLuGre : DTDFVocab:Model [
    base:desc "Simulink friction model implementing LuGre dynamics for the gearbox"
    DTDFVocab:inputTo SimulinkExecutorEnabler
]

// C6: Services
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Interactive dashboard visualization of measured and simulated torque, velocity and acceleration data"
    DTDFVocab:provides FrictionTrendInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction parameters from streamed data"
    DTDFVocab:provides FrictionParameterInsight, AdjustMotionControlAction
]

instance SimulationComparisonService : DTDFVocab:Service [
    base:desc "Comparison of simulated vs. measured torque/velocity traces to assess model fidelity"
    DTDFVocab:provides SimulationAccuracyInsight
]

// C17: Insights
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Identified friction parameters (static, kinetic, viscous) derived from live data"
]

instance FrictionTrendInsight : DTDFVocab:Insight [
    base:desc "Visual trends of friction parameters over time presented on the operator dashboard"
]

instance SimulationAccuracyInsight : DTDFVocab:Insight [
    base:desc "Quantitative assessment of simulation accuracy against measured data"
]

// C17: Actions
instance AdjustMotionControlAction : DTDFVocab:Action [
    base:desc "Automatic update of robot controller friction parameters to improve motion control accuracy"
    DTDFVocab:IsAutomatic true
]

// C15: System under study (environment and component)
instance MabiMaxVerticalAxis : DTDFVocab:Component [
    base:desc "First vertical axis of the MABI MAX 100 six‑axis industrial robot, including motor, cycloidal gearbox, and encoders"
]

instance SafetyCell : DTDFVocab:Component [
    base:desc "Safety cell limiting motion to ±90° with a maximum speed of 75°/s"
]

instance AxisEnvironment : DTDFVocab:Environment [
    base:contains MabiMaxVerticalAxis, SafetyCell
]

// C2: Acting components (none – passive digital shadow)
instance PassiveDigitalShadow : DTDFVocab:ActingComponent [
    base:desc "Passive, one‑way data consumer digital shadow; no actuators or control commands are issued"
]

// C12: Tooling and Enablers (already captured in Enabler section)

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow does not push data or commands back to the robot; it remains a one‑way data flow from PT to VT."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time (online) data acquisition and processing; the digital shadow updates friction estimates and visualizations on the fly as new sensor samples arrive."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow consisting of a Purpose element (FrictionDerivation), an Asset element (the first axis), multiple DataTrace/DataPoint elements (measured and simulated torque/velocity series), Source elements (sensor channels), Processing components (Simulation M, GW, GB) that consume input traces and produce output traces using the simulation models, all linked through the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operational stage – the digital shadow is created and used during runtime of the robot to monitor and improve motion accuracy; it does not cover design or manufacturing phases."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point to its source and processing model; comparison of simulated friction‑free behavior with measured data to assess model accuracy; use of manufacturer‑provided dynamic parameters in the simulation; ability to continuously re‑identify friction parameters to maintain validity over wear and temperature changes."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are streamed from the robot to the digital shadow using the MQTT protocol over the plant network."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation utilizes the Asset Administration Shell (AAS) standard for Industry 4.0 integration and follows SysML modeling conventions; the digital shadow concept is grounded in the Kritzinger et al. definition of digital shadows."
]
